import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.EntityGraph;
import java.util.List;

public interface ProductRepository extends JpaRepository<Product, String> {

    // @EntityGraph overrides default findAll() with LEFT JOIN for seller:
    @EntityGraph(attributePaths = {"seller"})
    List<Product> findAll();
    // Generates: SELECT p.*, s.*
    //            FROM products p LEFT JOIN sellers s ON p.seller_id = s.id

    // Works with any derived query method:
    @EntityGraph(attributePaths = {"seller"})
    List<Product> findByCategory(String category);
    // Generates: SELECT p.*, s.*
    //            FROM products p LEFT JOIN sellers s ON p.seller_id = s.id
    //            WHERE p.category = ?

    // Multiple associations:
    @EntityGraph(attributePaths = {"seller", "warehouse"})
    List<Product> findByPriceLessThan(double maxPrice);
}

// @EntityGraph vs JOIN FETCH:
// @EntityGraph: use when the base method already exists (findAll, findByX)
//               always LEFT JOIN (null associations are null, not an error)
//               no JPQL needed
// JOIN FETCH: use when writing custom JPQL anyway
//             INNER JOIN (association must exist)
//             more control in complex queries (WHERE, ORDER BY in same JPQL)

