import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.beans.factory.annotation.Autowired;
import org.hibernate.SessionFactory;
import jakarta.persistence.EntityManager;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.List;

@DataJpaTest
class OrderRepositoryN1Test {
    @Autowired OrderRepository repo;
    @Autowired TestEntityManager testEm;
    @Autowired EntityManager em;

    @BeforeEach void seed() {
        User u1 = testEm.persistAndFlush(new User("Aisha Sharma", "aisha@test.com"));
        User u2 = testEm.persistAndFlush(new User("Raj Patel",   "raj@test.com"));
        testEm.persistAndFlush(new Order(u1, "PLACED",   1500.0));
        testEm.persistAndFlush(new Order(u1, "DELIVERED", 800.0));
        testEm.persistAndFlush(new Order(u2, "PLACED",    400.0));
        testEm.clear();  // ← CRITICAL: evict L1 cache after seeding
    }

    @Test
    void findAllWithUser_exactlyOneQuery() {
        SessionFactory sf = em.getEntityManagerFactory()
            .unwrap(SessionFactory.class);
        sf.getStatistics().setStatisticsEnabled(true);
        sf.getStatistics().clear();

        // Execute and access associations:
        List<Order> orders = repo.findAllWithUser();
        orders.forEach(o -> {
            assertNotNull(o.getUser().getName());  // should NOT fire extra queries
        });

        long count = sf.getStatistics().getPreparedStatementCount();
        assertEquals(1, count,
            "N+1 detected: expected 1 query, got " + count);
    }
}

// N+1 CAUSE:
// List<Restaurant> restaurants = restaurantRepo.findAll(); // Query 1
// for (Restaurant r : restaurants) {
//     System.out.println(r.getOrders().size()); // N queries: SELECT * FROM orders WHERE restaurant_id=?
// }
// = N+1 for N restaurants

// FIX 1: JOIN FETCH with DISTINCT
// @Query("SELECT DISTINCT r FROM Restaurant r JOIN FETCH r.orders")
// Without DISTINCT: 10 restaurants × 100 orders = 1000 rows returned!
// → 1000 Restaurant objects (duplicates). DISTINCT deduplicates at Hibernate level.
// Use when: collection is small, no pagination needed

// FIX 2: @BatchSize on the collection:
import jakarta.persistence.*;
@Entity
public class Restaurant {
    @Id String id;
    String name;

    @OneToMany(mappedBy = "restaurant", fetch = FetchType.LAZY)
    @org.hibernate.annotations.BatchSize(size = 20)
    private java.util.List<Order> orders;
    // Without @BatchSize: N queries (one per restaurant)
    // With @BatchSize(20): SELECT * FROM orders WHERE restaurant_id IN (id1, ..., id20)
    // N/20 queries instead of N queries
}
// Use @BatchSize when: collection can be large, pagination is needed,
//                     or JOIN FETCH would create too much data

// WHEN TO USE EACH:
// JOIN FETCH DISTINCT: small collections, no pagination, must access all orders
// @BatchSize:          large collections, or when paginating restaurants
//                     cannot combine JOIN FETCH (OneToMany) + Pageable

public class NplusOneExample {
    public static void main(String[] args) {
        System.out.println("N+1 fix: JOIN FETCH DISTINCT for small collections");
        System.out.println("BatchSize: for large collections or with pagination");
    }
}

