import org.springframework.beans.factory.annotation.Value;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import java.util.List;

// 1. Interface-based projection (Spring creates proxy):
public interface TradeListView {
    String getSymbol();
    int    getQty();
    double getPrice();

    // Access nested association field using SpEL:
    @Value("#{target.user.name}")
    String getUserName();
}

// 2. Class-based DTO record:
public record TradeSummaryDto(
    String symbol,
    int qty,
    double price,
    String userName
) {}

// 3. Repository with projections:
public interface TradeRepository extends JpaRepository<Trade, String> {

    // Interface projection:
    List<TradeListView> findByStatus(String status);
    // → Spring generates query for only projected fields

    // Class-based DTO projection (most flexible):
    @Query("SELECT new com.codequest.TradeSummaryDto(" +
           "t.symbol, t.qty, t.price, t.user.name) " +
           "FROM Trade t WHERE t.status = :status")
    List<TradeSummaryDto> findSummaryByStatus(@Param("status") String status);
    // → 1 query, only loads needed columns (not all entity columns)
    // → No @Entity loaded — pure data transfer
}

// PROJECTION vs JOIN FETCH:
// JOIN FETCH: loads full @Entity objects (useful if you need to update them)
//             all columns loaded even if unused
// DTO Projection: read-only, select only needed columns
//                 more efficient for read-heavy list APIs
//                 can't update/save the result
// Rule: read-only API response → DTO projection
//       may need to modify the entity → JOIN FETCH

