// APPROACH 1 (BAD — triggers HHH90003004):
// @Query("SELECT DISTINCT r FROM Restaurant r JOIN FETCH r.orders")
// Page<Restaurant> findAllWithOrders(Pageable pageable);
// → HHH90003004: firstResult/maxResults specified with collection fetch;
//   applying in memory! ALL restaurants loaded before paginating!

@Entity
public class Restaurant {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    String name;

    // APPROACH 2 FIX: @BatchSize instead of JOIN FETCH
    @OneToMany(mappedBy="restaurant", fetch=FetchType.LAZY)
    @BatchSize(size=20)
    private List<Order> orders;
    // → repo.findAll(pageable) fires N/20 batched queries
    //   (SELECT * FROM orders WHERE restaurant_id IN (id1,...,id20))
    //   instead of N individual queries
    //   → safe with pagination!

    protected Restaurant(){}
    Restaurant(String n){name=n;}
    String getId(){return id;} String getName(){return name;}
    List<Order> getOrders(){return orders;}
}

public interface RestaurantRepository extends JpaRepository<Restaurant,String> {

    // APPROACH 2: @BatchSize, safe with Pageable:
    Page<Restaurant> findAll(Pageable pageable);
    // orders loaded via IN batches when accessed

    // APPROACH 3 FIX: 2-step — IDs first, then JOIN FETCH:
    @Query("SELECT r.id FROM Restaurant r")
    Page<String> findAllIds(Pageable pageable);  // Step 1: paginate on IDs

    @Query("SELECT DISTINCT r FROM Restaurant r JOIN FETCH r.orders WHERE r.id IN :ids")
    List<Restaurant> findAllWithOrders(@Param("ids") List<String> ids); // Step 2: fetch full
    // → 2 queries, correct pagination, no in-memory problem

    // WHEN TO USE WHICH:
    // @BatchSize: simpler code, slightly more queries, works with any Pageable
    // 2-step: more complex, exactly 2 queries, better for very large collections
    // JOIN FETCH DISTINCT (no Pageable): when you DON'T paginate the parent
}

